{
  "name": "PawPrint - Pet Journal",
  "description": "An elegant and simple application to track your pet's growth, health records, and profile details."
}

export interface PetProfile {
  name: string;
  breed: string;
  gender: 'Male' | 'Female' | 'Other';
  birthDate: string; // ISO string YYYY-MM-DD
  microchipId: string;
  photoUrl: string | null;
}

export interface PhysicalRecord {
  id: string;
  date: string;
  weight: number; // kg
  height?: number; // cm
  neck?: number; // cm
  chest?: number; // cm
  back?: number; // cm
  notes?: string;
}

export interface HealthRecord {
  id: string;
  type: 'Vaccine' | 'Deworming' | 'Vet Visit' | 'Other';
  date: string;
  title: string; // e.g., "Rabies Shot" or "Heartgard"
  location?: string;
  nextDueDate?: string; // For reminders
  notes?: string;
}

export type TabView = 'profile' | 'physical' | 'health';

export const calculateAge = (birthDateString: string): string => {
  if (!birthDateString) return 'Unknown Age';

  const birthDate = new Date(birthDateString);
  const today = new Date();

  let years = today.getFullYear() - birthDate.getFullYear();
  let months = today.getMonth() - birthDate.getMonth();

  if (months < 0 || (months === 0 && today.getDate() < birthDate.getDate())) {
    years--;
    months += 12;
  }

  // Adjust months if day hasn't passed yet in the current month
  if (today.getDate() < birthDate.getDate()) {
    months--;
  }

  if (years < 0) return 'Not born yet';

  if (years === 0) {
    return `${months} Months`;
  }

  return `${years} Yrs ${months > 0 ? `& ${months} Mos` : ''}`;
};

export const formatDate = (dateString: string): string => {
  if (!dateString) return '';
  return new Date(dateString).toLocaleDateString(undefined, {
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });
};

export const generateId = (): string => {
  return Math.random().toString(36).substr(2, 9);
};

import React, { useRef } from 'react';
import { PetProfile } from '../types';
import { calculateAge } from '../utils';
import { Camera, Calendar, Hash, Award } from 'lucide-react';

interface ProfileSectionProps {
  profile: PetProfile;
  setProfile: (profile: PetProfile) => void;
}

export const ProfileSection: React.FC<ProfileSectionProps> = ({ profile, setProfile }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleInputChange = (field: keyof PetProfile, value: string) => {
    setProfile({ ...profile, [field]: value });
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setProfile({ ...profile, photoUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const age = calculateAge(profile.birthDate);

  return (
    <div className="flex flex-col gap-8 animate-fade-in">
      {/* Photo & Main Info Card */}
      <div className="bg-white rounded-3xl p-6 shadow-sm border border-stone-100 flex flex-col items-center text-center relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-24 bg-gradient-to-b from-stone-100 to-white -z-0" />

        <div className="relative z-10 group">
          <div className="w-32 h-32 rounded-full border-4 border-white shadow-md overflow-hidden bg-stone-100 relative">
            {profile.photoUrl ? (
              <img src={profile.photoUrl} alt="Pet" className="w-full h-full object-cover" />
            ) : (
              <div className="w-full h-full flex items-center justify-center text-stone-300">
                <Camera size={40} />
              </div>
            )}
            <div 
              onClick={() => fileInputRef.current?.click()}
              className="absolute inset-0 bg-black/30 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer text-white font-medium backdrop-blur-sm"
            >
              Change Photo
            </div>
          </div>
          <input 
            type="file" 
            ref={fileInputRef} 
            onChange={handleImageUpload} 
            accept="image/*" 
            className="hidden" 
          />
        </div>

        <div className="mt-4 w-full">
           <input
            type="text"
            value={profile.name}
            onChange={(e) => handleInputChange('name', e.target.value)}
            placeholder="Pet Name"
            className="text-3xl font-serif text-stone-800 text-center w-full bg-transparent border-b border-transparent hover:border-stone-200 focus:border-stone-400 focus:outline-none transition-colors placeholder-stone-300"
          />
          <div className="text-stone-500 mt-1 flex justify-center gap-2 items-center">
            <span className="bg-stone-100 px-3 py-1 rounded-full text-sm font-medium text-stone-600">
               {age}
            </span>
          </div>
        </div>
      </div>

      {/* Details Form */}
      <div className="bg-white rounded-3xl p-6 shadow-sm border border-stone-100">
        <h3 className="text-lg font-medium text-stone-800 mb-6 flex items-center gap-2">
          <Award size={20} className="text-stone-400" />
          Basic Details
        </h3>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-xs font-semibold uppercase tracking-wider text-stone-400">Breed</label>
            <input
              type="text"
              value={profile.breed}
              onChange={(e) => handleInputChange('breed', e.target.value)}
              className="w-full p-3 bg-stone-50 rounded-xl border-none focus:ring-2 focus:ring-stone-200 text-stone-700 transition-all"
              placeholder="e.g. Golden Retriever"
            />
          </div>

          <div className="space-y-2">
             <label className="text-xs font-semibold uppercase tracking-wider text-stone-400">Gender</label>
             <div className="flex bg-stone-50 rounded-xl p-1">
                {(['Male', 'Female'] as const).map((g) => (
                  <button
                    key={g}
                    onClick={() => setProfile({...profile, gender: g})}
                    className={`flex-1 py-2 rounded-lg text-sm font-medium transition-all ${
                      profile.gender === g 
                        ? 'bg-white shadow-sm text-stone-800' 
                        : 'text-stone-400 hover:text-stone-600'
                    }`}
                  >
                    {g}
                  </button>
                ))}
             </div>
          </div>

          <div className="space-y-2">
            <label className="text-xs font-semibold uppercase tracking-wider text-stone-400 flex items-center gap-1">
              <Calendar size={14} /> Birth Date
            </label>
            <input
              type="date"
              value={profile.birthDate}
              onChange={(e) => handleInputChange('birthDate', e.target.value)}
              className="w-full p-3 bg-stone-50 rounded-xl border-none focus:ring-2 focus:ring-stone-200 text-stone-700"
            />
          </div>

          <div className="space-y-2">
            <label className="text-xs font-semibold uppercase tracking-wider text-stone-400 flex items-center gap-1">
              <Hash size={14} /> Microchip ID
            </label>
            <input
              type="text"
              value={profile.microchipId}
              onChange={(e) => handleInputChange('microchipId', e.target.value)}
              className="w-full p-3 bg-stone-50 rounded-xl border-none focus:ring-2 focus:ring-stone-200 text-stone-700 font-mono"
              placeholder="000-000-000"
            />
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { PhysicalRecord } from '../types';
import { generateId, formatDate } from '../utils';
import { Ruler, Weight, Plus, Trash2, ChevronDown, ChevronUp } from 'lucide-react';

interface PhysicalSectionProps {
  records: PhysicalRecord[];
  addRecord: (record: PhysicalRecord) => void;
  deleteRecord: (id: string) => void;
}

export const PhysicalSection: React.FC<PhysicalSectionProps> = ({ records, addRecord, deleteRecord }) => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [newRecord, setNewRecord] = useState<Partial<PhysicalRecord>>({
    date: new Date().toISOString().split('T')[0],
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newRecord.weight && newRecord.date) {
      addRecord({
        id: generateId(),
        date: newRecord.date,
        weight: Number(newRecord.weight),
        height: newRecord.height ? Number(newRecord.height) : undefined,
        neck: newRecord.neck ? Number(newRecord.neck) : undefined,
        chest: newRecord.chest ? Number(newRecord.chest) : undefined,
        back: newRecord.back ? Number(newRecord.back) : undefined,
        notes: newRecord.notes || '',
      });
      setIsFormOpen(false);
      setNewRecord({ date: new Date().toISOString().split('T')[0] });
    }
  };

  const sortedRecords = [...records].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  const latest = sortedRecords[0];

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Latest Stats Summary */}
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-stone-900 text-white p-5 rounded-2xl shadow-md">
            <div className="flex items-center gap-2 text-stone-400 text-sm font-medium mb-1">
               <Weight size={16} /> Current Weight
            </div>
            <div className="text-3xl font-serif">
              {latest?.weight ?? '--'} <span className="text-lg font-sans text-stone-400">kg</span>
            </div>
        </div>
        <div className="bg-white p-5 rounded-2xl shadow-sm border border-stone-100">
             <div className="flex items-center gap-2 text-stone-400 text-sm font-medium mb-1">
               <Ruler size={16} /> Latest Height
            </div>
            <div className="text-3xl font-serif text-stone-800">
              {latest?.height ?? '--'} <span className="text-lg font-sans text-stone-400">cm</span>
            </div>
        </div>
      </div>

      {/* Add Button */}
      {!isFormOpen && (
        <button 
          onClick={() => setIsFormOpen(true)}
          className="w-full py-4 rounded-xl border-2 border-dashed border-stone-300 text-stone-500 font-medium hover:border-stone-500 hover:text-stone-700 transition-colors flex items-center justify-center gap-2"
        >
          <Plus size={20} /> Log New Measurement
        </button>
      )}

      {/* Input Form */}
      {isFormOpen && (
        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-3xl shadow-sm border border-stone-100 space-y-4">
          <div className="flex justify-between items-center mb-2">
            <h3 className="font-serif text-xl text-stone-800">New Entry</h3>
            <button type="button" onClick={() => setIsFormOpen(false)} className="text-stone-400 hover:text-stone-600">Close</button>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="col-span-2">
              <label className="text-xs text-stone-500 uppercase font-bold">Date</label>
              <input 
                required
                type="date" 
                value={newRecord.date}
                onChange={e => setNewRecord({...newRecord, date: e.target.value})}
                className="w-full p-3 bg-stone-50 rounded-xl border-none focus:ring-1 focus:ring-stone-400"
              />
            </div>
            <div>
              <label className="text-xs text-stone-500 uppercase font-bold">Weight (kg)</label>
              <input 
                required
                type="number" step="0.1"
                placeholder="0.0"
                value={newRecord.weight || ''}
                onChange={e => setNewRecord({...newRecord, weight: Number(e.target.value)})}
                className="w-full p-3 bg-stone-50 rounded-xl border-none focus:ring-1 focus:ring-stone-400"
              />
            </div>
            <div>
              <label className="text-xs text-stone-500 uppercase font-bold">Height (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="0.0"
                value={newRecord.height || ''}
                onChange={e => setNewRecord({...newRecord, height: Number(e.target.value)})}
                className="w-full p-3 bg-stone-50 rounded-xl border-none focus:ring-1 focus:ring-stone-400"
              />
            </div>
             <div>
              <label className="text-xs text-stone-500 uppercase font-bold">Chest (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="Girth"
                value={newRecord.chest || ''}
                onChange={e => setNewRecord({...newRecord, chest: Number(e.target.value)})}
                className="w-full p-3 bg-stone-50 rounded-xl border-none focus:ring-1 focus:ring-stone-400"
              />
            </div>
            <div>
              <label className="text-xs text-stone-500 uppercase font-bold">Neck (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="Circumference"
                value={newRecord.neck || ''}
                onChange={e => setNewRecord({...newRecord, neck: Number(e.target.value)})}
                className="w-full p-3 bg-stone-50 rounded-xl border-none focus:ring-1 focus:ring-stone-400"
              />
            </div>
             <div>
              <label className="text-xs text-stone-500 uppercase font-bold">Back (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="Length"
                value={newRecord.back || ''}
                onChange={e => setNewRecord({...newRecord, back: Number(e.target.value)})}
                className="w-full p-3 bg-stone-50 rounded-xl border-none focus:ring-1 focus:ring-stone-400"
              />
            </div>
          </div>

          <button type="submit" className="w-full py-3 bg-stone-800 text-white rounded-xl font-medium hover:bg-stone-900 transition-colors">
            Save Record
          </button>
        </form>
      )}

      {/* History List */}
      <div className="space-y-3">
        {sortedRecords.length === 0 && !isFormOpen && (
          <p className="text-center text-stone-400 py-8">No records yet.</p>
        )}
        {sortedRecords.map((record) => (
          <MeasurementCard key={record.id} record={record} onDelete={() => deleteRecord(record.id)} />
        ))}
      </div>
    </div>
  );
};

const MeasurementCard: React.FC<{ record: PhysicalRecord; onDelete: () => void }> = ({ record, onDelete }) => {
  const [expanded, setExpanded] = useState(false);

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-stone-100 overflow-hidden transition-all hover:shadow-md">
      <div 
        onClick={() => setExpanded(!expanded)}
        className="p-4 flex justify-between items-center cursor-pointer"
      >
        <div className="flex gap-4 items-center">
            <div className="bg-stone-100 px-3 py-2 rounded-lg text-center min-w-[60px]">
                <div className="text-xs text-stone-500 uppercase">{new Date(record.date).toLocaleString('default', { month: 'short' })}</div>
                <div className="text-lg font-bold text-stone-800 leading-none">{new Date(record.date).getDate()}</div>
            </div>
            <div>
                <div className="text-stone-800 font-serif text-lg">{record.weight} kg</div>
                <div className="text-xs text-stone-400 flex gap-2">
                   {record.height && <span>H: {record.height}cm</span>}
                   {record.chest && <span>C: {record.chest}cm</span>}
                </div>
            </div>
        </div>
        <div className="text-stone-300">
           {expanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
        </div>
      </div>

      {expanded && (
        <div className="px-4 pb-4 bg-stone-50/50 pt-2 border-t border-stone-100">
          <div className="grid grid-cols-2 gap-y-2 text-sm text-stone-600 mb-4">
             <div>Neck: <span className="font-medium text-stone-800">{record.neck || '-'} cm</span></div>
             <div>Chest: <span className="font-medium text-stone-800">{record.chest || '-'} cm</span></div>
             <div>Back: <span className="font-medium text-stone-800">{record.back || '-'} cm</span></div>
             <div>Height: <span className="font-medium text-stone-800">{record.height || '-'} cm</span></div>
          </div>
          <button 
            onClick={(e) => { e.stopPropagation(); onDelete(); }}
            className="text-red-400 text-xs flex items-center gap-1 hover:text-red-600"
          >
            <Trash2 size={12} /> Delete Entry
          </button>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { HealthRecord } from '../types';
import { generateId, formatDate } from '../utils';
import { Syringe, Bug, Plus, MapPin, Clock, Trash2, Pill } from 'lucide-react';

interface HealthSectionProps {
  records: HealthRecord[];
  addRecord: (record: HealthRecord) => void;
  deleteRecord: (id: string) => void;
}

export const HealthSection: React.FC<HealthSectionProps> = ({ records, addRecord, deleteRecord }) => {
  const [activeType, setActiveType] = useState<'Vaccine' | 'Deworming'>('Vaccine');
  const [isFormOpen, setIsFormOpen] = useState(false);

  const [newRecord, setNewRecord] = useState<Partial<HealthRecord>>({
    date: new Date().toISOString().split('T')[0],
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newRecord.title && newRecord.date) {
      addRecord({
        id: generateId(),
        type: activeType,
        date: newRecord.date,
        title: newRecord.title,
        location: newRecord.location,
        nextDueDate: newRecord.nextDueDate,
        notes: newRecord.notes,
      });
      setIsFormOpen(false);
      setNewRecord({ date: new Date().toISOString().split('T')[0] });
    }
  };

  const filteredRecords = records
    .filter(r => r.type === activeType)
    .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

  // Check for upcoming records
  const upcoming = records.filter(r => r.nextDueDate && new Date(r.nextDueDate) > new Date()).sort((a,b) => new Date(a.nextDueDate!).getTime() - new Date(b.nextDueDate!).getTime());

  return (
    <div className="space-y-6 animate-fade-in">

      {/* Reminders Card */}
      {upcoming.length > 0 && (
         <div className="bg-amber-50 border border-amber-100 p-4 rounded-2xl flex items-start gap-3">
            <div className="bg-amber-100 p-2 rounded-full text-amber-600 mt-1">
               <Clock size={16} />
            </div>
            <div>
               <h4 className="text-amber-900 font-medium text-sm">Upcoming Due Date</h4>
               <p className="text-amber-700 text-sm">
                  {upcoming[0].title} is due on <span className="font-bold">{formatDate(upcoming[0].nextDueDate!)}</span>
               </p>
            </div>
         </div>
      )}

      {/* Tabs */}
      <div className="flex bg-stone-100 p-1 rounded-xl">
        <button 
          onClick={() => setActiveType('Vaccine')}
          className={`flex-1 py-2 rounded-lg text-sm font-medium flex items-center justify-center gap-2 transition-all ${activeType === 'Vaccine' ? 'bg-white shadow-sm text-stone-800' : 'text-stone-400'}`}
        >
          <Syringe size={16} /> Vaccinations
        </button>
        <button 
          onClick={() => setActiveType('Deworming')}
          className={`flex-1 py-2 rounded-lg text-sm font-medium flex items-center justify-center gap-2 transition-all ${activeType === 'Deworming' ? 'bg-white shadow-sm text-stone-800' : 'text-stone-400'}`}
        >
          <Bug size={16} /> Deworming
        </button>
      </div>

       {/* Add Button */}
       {!isFormOpen && (
        <button 
          onClick={() => setIsFormOpen(true)}
          className="w-full py-4 rounded-xl border-2 border-dashed border-stone-300 text-stone-500 font-medium hover:border-stone-500 hover:text-stone-700 transition-colors flex items-center justify-center gap-2"
        >
          <Plus size={20} /> Log {activeType}
        </button>
      )}

      {/* Form */}
      {isFormOpen && (
        <form onSubmit={handleSubmit} className="bg-white p-6 rounded-3xl shadow-sm border border-stone-100 space-y-4">
          <div className="flex justify-between items-center mb-2">
            <h3 className="font-serif text-xl text-stone-800">Add {activeType}</h3>
            <button type="button" onClick={() => setIsFormOpen(false)} className="text-stone-400 hover:text-stone-600">Close</button>
          </div>

          <div className="space-y-3">
             <div>
              <label className="text-xs text-stone-500 uppercase font-bold">Name</label>
              <input 
                required
                type="text" 
                placeholder={activeType === 'Vaccine' ? "e.g. Rabies, DHPP" : "e.g. Heartgard, Nexgard"}
                value={newRecord.title || ''}
                onChange={e => setNewRecord({...newRecord, title: e.target.value})}
                className="w-full p-3 bg-stone-50 rounded-xl border-none focus:ring-1 focus:ring-stone-400"
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="text-xs text-stone-500 uppercase font-bold">Date Administered</label>
                <input 
                  required
                  type="date" 
                  value={newRecord.date}
                  onChange={e => setNewRecord({...newRecord, date: e.target.value})}
                  className="w-full p-3 bg-stone-50 rounded-xl border-none focus:ring-1 focus:ring-stone-400"
                />
              </div>
               <div>
                <label className="text-xs text-stone-500 uppercase font-bold text-amber-600">Next Due Date</label>
                <input 
                  type="date" 
                  value={newRecord.nextDueDate || ''}
                  onChange={e => setNewRecord({...newRecord, nextDueDate: e.target.value})}
                  className="w-full p-3 bg-amber-50 rounded-xl border-none focus:ring-1 focus:ring-amber-400 text-amber-900"
                />
              </div>
            </div>

            <div>
              <label className="text-xs text-stone-500 uppercase font-bold">Clinic / Location</label>
              <div className="relative">
                <MapPin size={16} className="absolute left-3 top-3.5 text-stone-400" />
                <input 
                  type="text" 
                  placeholder="e.g. City Vet Clinic"
                  value={newRecord.location || ''}
                  onChange={e => setNewRecord({...newRecord, location: e.target.value})}
                  className="w-full p-3 pl-10 bg-stone-50 rounded-xl border-none focus:ring-1 focus:ring-stone-400"
                />
              </div>
            </div>
          </div>

           <button type="submit" className="w-full py-3 bg-stone-800 text-white rounded-xl font-medium hover:bg-stone-900 transition-colors">
            Save Record
          </button>
        </form>
      )}

      {/* Timeline List */}
      <div className="relative border-l-2 border-stone-200 ml-4 space-y-8 pl-6 py-2">
         {filteredRecords.length === 0 && !isFormOpen && (
             <p className="text-stone-400 text-sm italic">No records found.</p>
         )}
         {filteredRecords.map((record) => (
           <div key={record.id} className="relative group">
              {/* Dot */}
              <div className="absolute -left-[31px] top-1 w-4 h-4 rounded-full bg-white border-4 border-stone-300 group-hover:border-stone-500 transition-colors" />

              <div className="bg-white p-4 rounded-xl shadow-sm border border-stone-100 hover:shadow-md transition-shadow">
                  <div className="flex justify-between items-start">
                     <div>
                        <h4 className="font-serif text-lg text-stone-800">{record.title}</h4>
                        <p className="text-xs text-stone-400 font-medium uppercase tracking-wide mb-2">{formatDate(record.date)}</p>
                     </div>
                     <button onClick={() => deleteRecord(record.id)} className="text-stone-300 hover:text-red-400">
                        <Trash2 size={16} />
                     </button>
                  </div>

                  {record.location && (
                    <div className="flex items-center gap-1 text-sm text-stone-500 mb-1">
                       <MapPin size={14} /> {record.location}
                    </div>
                  )}

                  {record.nextDueDate && (
                     <div className="mt-3 inline-flex items-center gap-1.5 px-2.5 py-1 rounded-md bg-stone-100 text-stone-600 text-xs font-medium">
                        <Clock size={12} /> Next due: {formatDate(record.nextDueDate)}
                     </div>
                  )}
              </div>
           </div>
         ))}
      </div>

    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { PetProfile, PhysicalRecord, HealthRecord, TabView } from './types';
import { ProfileSection } from './components/ProfileSection';
import { PhysicalSection } from './components/PhysicalSection';
import { HealthSection } from './components/HealthSection';
import { User, Activity, Heart, PawPrint } from 'lucide-react';

const App: React.FC = () => {
  // --- State ---
  const [activeTab, setActiveTab] = useState<TabView>('profile');

  const [profile, setProfile] = useState<PetProfile>(() => {
    const saved = localStorage.getItem('pawprint_profile');
    return saved ? JSON.parse(saved) : {
      name: '',
      breed: '',
      gender: 'Male',
      birthDate: '',
      microchipId: '',
      photoUrl: null,
