import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { PetProfile, PhysicalRecord, ChatMessage } from '../types';
import { calculateAge } from '../utils';
import { Send, Sparkles, Bot, User as UserIcon } from 'lucide-react';

interface ChatSectionProps {
  profile: PetProfile;
  latestWeight?: number;
}

export const ChatSection: React.FC<ChatSectionProps> = ({ profile, latestWeight }) => {
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Construct system context based on pet profile
  const getSystemContext = () => {
    const age = calculateAge(profile.birthDate);
    const weightInfo = latestWeight ? `Current weight is ${latestWeight}kg.` : 'Weight is unknown.';
    const clinicInfo = profile.vetContact?.clinicName 
      ? `Their vet is at ${profile.vetContact.clinicName} (Phone: ${profile.vetContact.phone}).` 
      : '';

    return `You are a helpful, warm, and knowledgeable veterinary assistant for a pet owner.
    The pet's name is ${profile.name || 'the pet'}.
    Species/Breed: ${profile.breed || 'Unknown'}.
    Gender: ${profile.gender}.
    Age: ${age}.
    ${weightInfo}
    ${clinicInfo}

    Answer questions concisely and with a friendly tone. 
    If the question is a medical emergency, advise them to contact their vet immediately.
    Use formatting like bullet points for readability if needed.
    `;
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // We create a new chat history for context, injecting the system instruction
      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
          systemInstruction: getSystemContext(),
        },
        history: messages.map(m => ({
          role: m.role,
          parts: [{ text: m.text }]
        })),
      });

      const result = await chat.sendMessageStream({ message: userMsg });

      let fullResponse = "";

      // Temporary message for streaming
      setMessages(prev => [...prev, { role: 'model', text: '' }]);

      for await (const chunk of result) {
        const c = chunk as GenerateContentResponse;
        const text = c.text;
        if (text) {
          fullResponse += text;
          setMessages(prev => {
            const newArr = [...prev];
            newArr[newArr.length - 1] = { role: 'model', text: fullResponse };
            return newArr;
          });
        }
      }
    } catch (error) {
      console.error("Chat error:", error);
      setMessages(prev => [...prev, { role: 'model', text: "I'm sorry, I'm having trouble connecting right now. Please try again later." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[calc(100vh-200px)] animate-fade-in">
      <div className="bg-gradient-to-r from-stone-800 to-stone-700 text-white p-4 rounded-2xl shadow-md mb-4 flex items-center gap-3">
        <div className="bg-white/10 p-2 rounded-full">
          <Sparkles size={20} className="text-yellow-300" />
        </div>
        <div>
          <h3 className="font-serif text-lg leading-tight">AI Assistant</h3>
          <p className="text-xs text-stone-300">Ask about {profile.name || 'your pet'}'s health or care</p>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto space-y-4 p-2 custom-scrollbar">
        {messages.length === 0 && (
          <div className="text-center text-stone-400 mt-10 px-6">
            <Bot size={48} className="mx-auto mb-4 opacity-50" />
            <p className="text-sm">Hello! I know {profile.name} is a {profile.breed || 'pet'}. Ask me anything about diet, behavior, or vaccines!</p>
          </div>
        )}

        {messages.map((msg, idx) => (
          <div key={idx} className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
            <div className={`w-8 h-8 rounded-full flex-shrink-0 flex items-center justify-center ${msg.role === 'user' ? 'bg-stone-800 text-white' : 'bg-white border border-stone-200 text-stone-600'}`}>
              {msg.role === 'user' ? <UserIcon size={14} /> : <Bot size={16} />}
            </div>
            <div className={`max-w-[80%] p-3 rounded-2xl text-sm leading-relaxed shadow-sm ${
              msg.role === 'user' 
                ? 'bg-stone-800 text-white rounded-tr-none' 
                : 'bg-white border border-stone-100 text-stone-800 rounded-tl-none'
            }`}>
              {msg.text}
            </div>
          </div>
        ))}
        {isLoading && (
           <div className="flex gap-3">
             <div className="w-8 h-8 rounded-full bg-white border border-stone-200 flex items-center justify-center text-stone-600">
                <Bot size={16} />
             </div>
             <div className="bg-white border border-stone-100 p-3 rounded-2xl rounded-tl-none shadow-sm">
                <div className="flex gap-1">
                  <span className="w-2 h-2 bg-stone-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></span>
                  <span className="w-2 h-2 bg-stone-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></span>
                  <span className="w-2 h-2 bg-stone-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></span>
                </div>
             </div>
           </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <div className="mt-4 relative">
        <input
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && handleSend()}
          placeholder="Ask a question..."
          className="w-full pl-4 pr-12 py-4 bg-white rounded-xl shadow-sm border border-stone-200 focus:outline-none focus:border-stone-400 focus:ring-1 focus:ring-stone-400 transition-all text-stone-800 placeholder-stone-400"
        />
        <button 
          onClick={handleSend}
          disabled={!input.trim() || isLoading}
          className="absolute right-2 top-2 p-2 bg-stone-800 text-white rounded-lg hover:bg-stone-900 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
        >
          <Send size={18} />
        </button>
      </div>
    </div>
  );
};

