import React, { useState } from 'react';
import { PhysicalRecord } from '../types';
import { generateId, formatDate } from '../utils';
import { Ruler, Weight, Plus, Trash2, ChevronDown, ChevronUp, X } from 'lucide-react';

interface PhysicalSectionProps {
  records: PhysicalRecord[];
  addRecord: (record: PhysicalRecord) => void;
  deleteRecord: (id: string) => void;
}

export const PhysicalSection: React.FC<PhysicalSectionProps> = ({ records, addRecord, deleteRecord }) => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [newRecord, setNewRecord] = useState<Partial<PhysicalRecord>>({
    date: new Date().toISOString().split('T')[0],
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newRecord.weight && newRecord.date) {
      addRecord({
        id: generateId(),
        date: newRecord.date,
        weight: Number(newRecord.weight),
        height: newRecord.height ? Number(newRecord.height) : undefined,
        neck: newRecord.neck ? Number(newRecord.neck) : undefined,
        chest: newRecord.chest ? Number(newRecord.chest) : undefined,
        back: newRecord.back ? Number(newRecord.back) : undefined,
        notes: newRecord.notes || '',
      });
      setIsFormOpen(false);
      setNewRecord({ date: new Date().toISOString().split('T')[0] });
    }
  };

  const sortedRecords = [...records].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  const latest = sortedRecords[0];

  return (
    <div className="space-y-8 animate-slide-up">
      {/* Latest Stats Summary - Minimal Cards */}
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-ink text-paper p-6 rounded-[2rem] shadow-lg shadow-ink/10 flex flex-col justify-between aspect-square">
            <div className="flex items-center gap-2 text-paper/60 text-xs font-semibold tracking-widest uppercase">
               <Weight size={14} /> Weight
            </div>
            <div className="mt-2">
              <span className="text-4xl font-serif leading-none">{latest?.weight ?? '--'}</span>
              <span className="text-sm ml-1 text-paper/60">kg</span>
            </div>
        </div>
        <div className="bg-white p-6 rounded-[2rem] shadow-sm flex flex-col justify-between aspect-square border border-white/50">
             <div className="flex items-center gap-2 text-pencil/80 text-xs font-semibold tracking-widest uppercase">
               <Ruler size={14} /> Height
            </div>
            <div className="mt-2">
              <span className="text-4xl font-serif text-ink leading-none">{latest?.height ?? '--'}</span>
              <span className="text-sm ml-1 text-pencil">cm</span>
            </div>
        </div>
      </div>

      {/* Add Button */}
      {!isFormOpen && (
        <button 
          onClick={() => setIsFormOpen(true)}
          className="w-full py-4 rounded-2xl border border-sand bg-white/50 text-pencil font-medium hover:bg-white hover:border-warm transition-all flex items-center justify-center gap-2 shadow-sm"
        >
          <Plus size={18} /> Record Measurement
        </button>
      )}

      {/* Input Form - Modal Style Inline */}
      {isFormOpen && (
        <form onSubmit={handleSubmit} className="bg-card p-8 rounded-[2rem] shadow-xl shadow-warm/20 border border-white/50 space-y-6 relative animate-fade-in">
          <div className="flex justify-between items-center mb-4">
            <h3 className="font-serif text-2xl text-ink">New Entry</h3>
            <button type="button" onClick={() => setIsFormOpen(false)} className="w-8 h-8 rounded-full bg-paper flex items-center justify-center text-pencil hover:bg-sand transition-colors">
                <X size={16}/>
            </button>
          </div>

          <div className="grid grid-cols-2 gap-6">
            <div className="col-span-2 group">
              <label className="text-xs text-pencil font-semibold tracking-widest uppercase mb-2 block group-focus-within:text-ink">Date</label>
              <input 
                required
                type="date" 
                value={newRecord.date}
                onChange={e => setNewRecord({...newRecord, date: e.target.value})}
                className="w-full py-3 px-4 bg-paper rounded-xl border-none focus:ring-1 focus:ring-warm text-ink"
              />
            </div>
            <div className="group">
              <label className="text-xs text-pencil font-semibold tracking-widest uppercase mb-2 block group-focus-within:text-ink">Weight (kg)</label>
              <input 
                required
                type="number" step="0.1"
                placeholder="0.0"
                value={newRecord.weight || ''}
                onChange={e => setNewRecord({...newRecord, weight: Number(e.target.value)})}
                className="w-full py-3 px-4 bg-paper rounded-xl border-none focus:ring-1 focus:ring-warm text-ink text-lg"
              />
            </div>
            <div className="group">
              <label className="text-xs text-pencil font-semibold tracking-widest uppercase mb-2 block group-focus-within:text-ink">Height (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="0.0"
                value={newRecord.height || ''}
                onChange={e => setNewRecord({...newRecord, height: Number(e.target.value)})}
                className="w-full py-3 px-4 bg-paper rounded-xl border-none focus:ring-1 focus:ring-warm text-ink text-lg"
              />
            </div>
             <div className="group">
              <label className="text-xs text-pencil font-semibold tracking-widest uppercase mb-2 block group-focus-within:text-ink">Chest (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="Girth"
                value={newRecord.chest || ''}
                onChange={e => setNewRecord({...newRecord, chest: Number(e.target.value)})}
                className="w-full py-3 px-4 bg-paper rounded-xl border-none focus:ring-1 focus:ring-warm text-ink text-lg"
              />
            </div>
            <div className="group">
              <label className="text-xs text-pencil font-semibold tracking-widest uppercase mb-2 block group-focus-within:text-ink">Neck (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="Circle"
                value={newRecord.neck || ''}
                onChange={e => setNewRecord({...newRecord, neck: Number(e.target.value)})}
                className="w-full py-3 px-4 bg-paper rounded-xl border-none focus:ring-1 focus:ring-warm text-ink text-lg"
              />
            </div>
             <div className="group">
              <label className="text-xs text-pencil font-semibold tracking-widest uppercase mb-2 block group-focus-within:text-ink">Back (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="Length"
                value={newRecord.back || ''}
                onChange={e => setNewRecord({...newRecord, back: Number(e.target.value)})}
                className="w-full py-3 px-4 bg-paper rounded-xl border-none focus:ring-1 focus:ring-warm text-ink text-lg"
              />
            </div>
          </div>

          <button type="submit" className="w-full py-4 bg-ink text-paper rounded-xl font-medium hover:bg-ink/90 transition-colors shadow-lg shadow-ink/20 tracking-wide text-sm uppercase">
            Save Record
          </button>
        </form>
      )}

      {/* History List - Clean Timeline */}
      <div className="space-y-4">
        {sortedRecords.length === 0 && !isFormOpen && (
          <p className="text-center text-pencil/50 py-12 text-sm italic">No measurements recorded yet.</p>
        )}
        {sortedRecords.map((record) => (
          <MeasurementCard key={record.id} record={record} onDelete={() => deleteRecord(record.id)} />
        ))}
      </div>
    </div>
  );
};

