import React, { useState, useMemo } from 'react';
import { PhysicalRecord } from '../types';
import { generateId, formatDate, formatMonthYear } from '../utils';
import { Ruler, Weight, Plus, Trash2, ChevronDown, ChevronUp, X, Calendar as CalendarIcon } from 'lucide-react';

interface PhysicalSectionProps {
  records: PhysicalRecord[];
  addRecord: (record: PhysicalRecord) => void;
  deleteRecord: (id: string) => void;
}

export const PhysicalSection: React.FC<PhysicalSectionProps> = ({ records, addRecord, deleteRecord }) => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [newRecord, setNewRecord] = useState<Partial<PhysicalRecord>>({
    date: new Date().toISOString().split('T')[0],
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newRecord.weight && newRecord.date) {
      addRecord({
        id: generateId(),
        date: newRecord.date,
        weight: Number(newRecord.weight),
        height: newRecord.height ? Number(newRecord.height) : undefined,
        neck: newRecord.neck ? Number(newRecord.neck) : undefined,
        chest: newRecord.chest ? Number(newRecord.chest) : undefined,
        back: newRecord.back ? Number(newRecord.back) : undefined,
        notes: newRecord.notes || '',
      });
      setIsFormOpen(false);
      setNewRecord({ date: new Date().toISOString().split('T')[0] });
    }
  };

  const sortedRecords = [...records].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  const latest = sortedRecords[0];

  // Group records by Month Year
  const groupedRecords = useMemo(() => {
    const groups: Record<string, PhysicalRecord[]> = {};
    sortedRecords.forEach(record => {
      const date = new Date(record.date);
      const key = `${date.getFullYear()}-${date.getMonth()}`; // unique key
      if (!groups[key]) groups[key] = [];
      groups[key].push(record);
    });
    return groups;
  }, [sortedRecords]);

  // Sort keys descending
  const sortedKeys = Object.keys(groupedRecords).sort((a, b) => {
    const [yearA, monthA] = a.split('-').map(Number);
    const [yearB, monthB] = b.split('-').map(Number);
    return new Date(yearB, monthB).getTime() - new Date(yearA, monthA).getTime();
  });

  return (
    <div className="space-y-8 animate-slide-up">
      {/* Latest Stats Summary */}
      <div className="grid grid-cols-2 gap-4">
        <div className="bg-ink text-paper p-6 rounded-[2rem] shadow-lg shadow-ink/10 flex flex-col justify-between aspect-square">
            <div className="flex items-center gap-2 text-paper/60 text-xs font-semibold tracking-widest uppercase font-sans">
               <Weight size={14} /> Weight
            </div>
            <div className="mt-2">
              <span className="text-4xl font-fangsong leading-none">{latest?.weight ?? '--'}</span>
              <span className="text-sm ml-1 text-paper/60 font-fangsong">kg</span>
            </div>
        </div>
        <div className="bg-white p-6 rounded-[2rem] shadow-sm flex flex-col justify-between aspect-square border border-white/50">
             <div className="flex items-center gap-2 text-pencil/80 text-xs font-semibold tracking-widest uppercase font-sans">
               <Ruler size={14} /> Height
            </div>
            <div className="mt-2">
              <span className="text-4xl font-fangsong text-ink leading-none">{latest?.height ?? '--'}</span>
              <span className="text-sm ml-1 text-pencil font-fangsong">cm</span>
            </div>
        </div>
      </div>

      {/* Add Button */}
      {!isFormOpen && (
        <button 
          onClick={() => setIsFormOpen(true)}
          className="w-full py-4 rounded-2xl border border-sand bg-white/50 text-pencil font-medium hover:bg-white hover:border-warm transition-all flex items-center justify-center gap-2 shadow-sm font-sans"
        >
          <Plus size={18} /> Record Measurement
        </button>
      )}

      {/* Input Form */}
      {isFormOpen && (
        <form onSubmit={handleSubmit} className="bg-card p-8 rounded-[2rem] shadow-xl shadow-warm/20 border border-white/50 space-y-6 relative animate-fade-in">
          <div className="flex justify-between items-center mb-4">
            <h3 className="font-fangsong text-2xl text-ink">New Entry</h3>
            <button type="button" onClick={() => setIsFormOpen(false)} className="w-8 h-8 rounded-full bg-paper flex items-center justify-center text-pencil hover:bg-sand transition-colors">
                <X size={16}/>
            </button>
          </div>

          <div className="grid grid-cols-2 gap-6">
            <div className="col-span-2 group">
              <label className="text-xs text-pencil font-semibold tracking-widest uppercase mb-2 block group-focus-within:text-ink font-sans">Date</label>
              <input 
                required
                type="date" 
                value={newRecord.date}
                onChange={e => setNewRecord({...newRecord, date: e.target.value})}
                className="w-full py-3 px-4 bg-paper rounded-xl border-none focus:ring-1 focus:ring-warm text-ink font-fangsong"
              />
            </div>
            <div className="group">
              <label className="text-xs text-pencil font-semibold tracking-widest uppercase mb-2 block group-focus-within:text-ink font-sans">Weight (kg)</label>
              <input 
                required
                type="number" step="0.1"
                placeholder="0.0"
                value={newRecord.weight || ''}
                onChange={e => setNewRecord({...newRecord, weight: Number(e.target.value)})}
                className="w-full py-3 px-4 bg-paper rounded-xl border-none focus:ring-1 focus:ring-warm text-ink text-lg font-fangsong"
              />
            </div>
            <div className="group">
              <label className="text-xs text-pencil font-semibold tracking-widest uppercase mb-2 block group-focus-within:text-ink font-sans">Height (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="0.0"
                value={newRecord.height || ''}
                onChange={e => setNewRecord({...newRecord, height: Number(e.target.value)})}
                className="w-full py-3 px-4 bg-paper rounded-xl border-none focus:ring-1 focus:ring-warm text-ink text-lg font-fangsong"
              />
            </div>
             <div className="group">
              <label className="text-xs text-pencil font-semibold tracking-widest uppercase mb-2 block group-focus-within:text-ink font-sans">Chest (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="Girth"
                value={newRecord.chest || ''}
                onChange={e => setNewRecord({...newRecord, chest: Number(e.target.value)})}
                className="w-full py-3 px-4 bg-paper rounded-xl border-none focus:ring-1 focus:ring-warm text-ink text-lg font-fangsong"
              />
            </div>
            <div className="group">
              <label className="text-xs text-pencil font-semibold tracking-widest uppercase mb-2 block group-focus-within:text-ink font-sans">Neck (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="Circle"
                value={newRecord.neck || ''}
                onChange={e => setNewRecord({...newRecord, neck: Number(e.target.value)})}
                className="w-full py-3 px-4 bg-paper rounded-xl border-none focus:ring-1 focus:ring-warm text-ink text-lg font-fangsong"
              />
            </div>
             <div className="group">
              <label className="text-xs text-pencil font-semibold tracking-widest uppercase mb-2 block group-focus-within:text-ink font-sans">Back (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="Length"
                value={newRecord.back || ''}
                onChange={e => setNewRecord({...newRecord, back: Number(e.target.value)})}
                className="w-full py-3 px-4 bg-paper rounded-xl border-none focus:ring-1 focus:ring-warm text-ink text-lg font-fangsong"
              />
            </div>
          </div>

          <button type="submit" className="w-full py-4 bg-ink text-paper rounded-xl font-medium hover:bg-ink/90 transition-colors shadow-lg shadow-ink/20 tracking-wide text-sm uppercase font-sans">
            Save Record
          </button>
        </form>
      )}

      {/* History List - Grouped by Month */}
      <div className="space-y-8">
        {sortedRecords.length === 0 && !isFormOpen && (
          <p className="text-center text-pencil/50 py-12 text-sm italic font-fangsong">No measurements recorded yet.</p>
        )}

        {sortedKeys.map(key => {
           const [year, month] = key.split('-');
           const groupDate = new Date(Number(year), Number(month));

           return (
             <div key={key} className="space-y-4">
                {/* Month Header */}
                <div className="flex items-center gap-3 sticky top-[4.5rem] bg-paper/95 backdrop-blur-sm z-10 py-2">
                   <div className="h-px flex-1 bg-warm/50"></div>
                   <h3 className="text-pencil font-fangsong text-lg flex items-center gap-2">
                     <CalendarIcon size={16} />
                     {formatMonthYear(groupDate.toISOString())}
                   </h3>
                   <div className="h-px flex-1 bg-warm/50"></div>
                </div>

                {/* Records in this month */}
                <div className="space-y-4">
                  {groupedRecords[key].map(record => (
                     <MeasurementCard key={record.id} record={record} onDelete={() => deleteRecord(record.id)} />
                  ))}
                </div>
             </div>
           );
        })}
      </div>
    </div>
  );
};

const MeasurementCard: React.FC<{ record: PhysicalRecord; onDelete: () => void }> = ({ record, onDelete }) => {
  const [expanded, setExpanded] = useState(false);
  const dateObj = new Date(record.date);

  return (
    <div className="bg-card rounded-2xl shadow-sm border border-sand/50 overflow-hidden transition-all hover:shadow-md hover:border-warm">
      <div 
        onClick={() => setExpanded(!expanded)}
        className="p-5 flex justify-between items-center cursor-pointer"
      >
        <div className="flex gap-5 items-center">
            <div className="text-center min-w-[50px] font-fangsong">
                <div className="text-[12px] text-pencil font-bold tracking-widest uppercase mb-0.5">{dateObj.toLocaleString('en-US', { weekday: 'short' })}</div>
                <div className="text-2xl text-ink leading-none">{dateObj.getDate()}</div>
            </div>
            <div className="h-8 w-px bg-sand/60"></div>
            <div>
                <div className="text-ink text-lg font-medium font-fangsong">{record.weight} <span className="text-sm text-pencil">kg</span></div>
                {(record.height || record.chest) && (
                  <div className="text-xs text-pencil/70 flex gap-3 mt-0.5 font-sans">
                     {record.height && <span>H: {record.height}</span>}
                     {record.chest && <span>C: {record.chest}</span>}
                  </div>
                )}
            </div>
        </div>
        <div className="text-warm hover:text-pencil transition-colors">
           {expanded ? <ChevronUp size={18} /> : <ChevronDown size={18} />}
        </div>
      </div>

      {expanded && (
        <div className="px-5 pb-5 pt-2 bg-paper/30">
          <div className="grid grid-cols-2 gap-y-3 gap-x-4 text-sm text-pencil mb-4 font-fangsong">
             {record.neck && <div className="flex justify-between border-b border-sand/50 pb-1"><span>Neck</span> <span className="font-medium text-ink">{record.neck} cm</span></div>}
             {record.chest && <div className="flex justify-between border-b border-sand/50 pb-1"><span>Chest</span> <span className="font-medium text-ink">{record.chest} cm</span></div>}
             {record.back && <div className="flex justify-between border-b border-sand/50 pb-1"><span>Back</span> <span className="font-medium text-ink">{record.back} cm</span></div>}
             {record.height && <div className="flex justify-between border-b border-sand/50 pb-1"><span>Height</span> <span className="font-medium text-ink">{record.height} cm</span></div>}
          </div>
          <button 
            onClick={(e) => { e.stopPropagation(); onDelete(); }}
            className="text-red-400 text-xs flex items-center gap-1.5 hover:text-red-600 transition-colors uppercase tracking-wider font-semibold font-sans"
          >
            <Trash2 size={12} /> Delete Entry
          </button>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
