                  type="date" 
                  value={newRecord.nextDueDate || ''}
                  onChange={e => setNewRecord({...newRecord, nextDueDate: e.target.value})}
                  className="w-full py-3 px-4 bg-[#FAF6F2] rounded-xl border-none focus:ring-1 focus:ring-clay text-ink font-fangsong"
                />
              </div>
            </div>

            <div className="group">
              <label className="text-xs text-pencil font-semibold tracking-widest uppercase mb-2 block group-focus-within:text-ink font-sans">Location</label>
              <div className="relative">
                <MapPin size={16} className="absolute left-4 top-3.5 text-warm" />
                <input 
                  type="text" 
                  placeholder="e.g. City Vet Clinic"
                  value={newRecord.location || ''}
                  onChange={e => setNewRecord({...newRecord, location: e.target.value})}
                  className="w-full py-3 pl-11 pr-4 bg-paper rounded-xl border-none focus:ring-1 focus:ring-warm text-ink placeholder-warm font-fangsong"
                />
              </div>
            </div>
          </div>

           <button type="submit" className="w-full py-4 bg-ink text-paper rounded-xl font-medium hover:bg-ink/90 transition-colors shadow-lg shadow-ink/20 tracking-wide text-sm uppercase font-sans">
            Save Record
          </button>
        </form>
      )}

      {/* Timeline List - Grouped by Month */}
      <div className="pl-4 space-y-0">
         {filteredRecords.length === 0 && !isFormOpen && (
             <p className="text-pencil/50 text-sm italic py-8 text-center font-fangsong">No records logged.</p>
         )}

         {sortedKeys.map(key => {
            const [year, month] = key.split('-');
            const groupDate = new Date(Number(year), Number(month));

            return (
              <div key={key} className="mb-8 last:mb-0">
                 {/* Month Separator */}
                 <div className="flex items-center gap-3 mb-6">
                    <span className="text-pencil/80 font-fangsong text-sm uppercase tracking-widest">
                      {formatMonthYear(groupDate.toISOString())}
                    </span>
                    <div className="h-px flex-1 bg-sand"></div>
                 </div>

                 {groupedRecords[key].map((record, idx) => (
                    <div key={record.id} className="relative pl-8 pb-8 last:pb-0">
                        {/* Line */}
                        <div className="absolute left-[5px] top-3 bottom-0 w-px bg-sand/80"></div>
                        {/* Dot */}
                        <div className="absolute left-0 top-2 w-[11px] h-[11px] rounded-full bg-paper border-2 border-warm z-10" />

                        <div className="bg-card p-5 rounded-2xl shadow-sm border border-sand/30 hover:shadow-md transition-shadow group">
                            <div className="flex justify-between items-start mb-2">
                              <div>
                                  <h4 className="font-fangsong text-lg text-ink leading-tight">{record.title}</h4>
                                  <span className="text-xs text-pencil font-medium uppercase tracking-wide bg-paper px-2 py-0.5 rounded-md mt-1 inline-block font-sans">
                                    {formatDate(record.date)}
                                  </span>
                              </div>
                              <button onClick={() => deleteRecord(record.id)} className="text-warm hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity">
                                  <Trash2 size={16} />
                              </button>
                            </div>

                            {(record.location || record.nextDueDate) && (
                                <div className="flex flex-col gap-1.5 mt-3 pt-3 border-t border-sand/30">
                                    {record.location && (
                                      <div className="flex items-center gap-1.5 text-sm text-pencil font-fangsong">
                                      <MapPin size={14} className="text-warm" /> {record.location}
                                      </div>
                                  )}
                                  {record.nextDueDate && (
                                      <div className="flex items-center gap-1.5 text-sm text-clay font-medium font-fangsong">
                                          <Clock size={14} /> Next due: {formatDate(record.nextDueDate)}
                                      </div>
                                  )}
                                </div>
                            )}
                        </div>
                    </div>
                 ))}
              </div>
            )
         })}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { PetProfile, PhysicalRecord, HealthRecord, TabView } from './types';
import { ProfileSection } from './components/ProfileSection';
import { PhysicalSection } from './components/PhysicalSection';
import { HealthSection } from './components/HealthSection';
import { ChatSection } from './components/ChatSection';
import { User, Activity, Heart, PawPrint, MessageCircle } from 'lucide-react';

const App: React.FC = () => {
  // --- State ---
  const [activeTab, setActiveTab] = useState<TabView>('profile');
  const [scrolled, setScrolled] = useState(false);

  const [profile, setProfile] = useState<PetProfile>(() => {
    const saved = localStorage.getItem('pawprint_profile');
    return saved ? JSON.parse(saved) : {
      name: '',
      breed: '',
      gender: 'Male',
      birthDate: '',
      microchipId: '',
      photoUrl: null,
      vetContact: {
        clinicName: '',
        phone: '',
        address: ''
      }
    };
  });

  const [physicalRecords, setPhysicalRecords] = useState<PhysicalRecord[]>(() => {
    const saved = localStorage.getItem('pawprint_physical');
    return saved ? JSON.parse(saved) : [];
  });

  const [healthRecords, setHealthRecords] = useState<HealthRecord[]>(() => {
    const saved = localStorage.getItem('pawprint_health');
    return saved ? JSON.parse(saved) : [];
  });

  // --- Effects ---
  useEffect(() => localStorage.setItem('pawprint_profile', JSON.stringify(profile)), [profile]);
  useEffect(() => localStorage.setItem('pawprint_physical', JSON.stringify(physicalRecords)), [physicalRecords]);
  useEffect(() => localStorage.setItem('pawprint_health', JSON.stringify(healthRecords)), [healthRecords]);

  // Scroll effect for header
  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // --- Handlers ---
  const addPhysicalRecord = (record: PhysicalRecord) => setPhysicalRecords([...physicalRecords, record]);
  const deletePhysicalRecord = (id: string) => setPhysicalRecords(physicalRecords.filter(r => r.id !== id));

  const addHealthRecord = (record: HealthRecord) => setHealthRecords([...healthRecords, record]);
  const deleteHealthRecord = (id: string) => setHealthRecords(healthRecords.filter(r => r.id !== id));

  // Get latest weight for chat context
  const latestWeight = physicalRecords.length > 0 
    ? physicalRecords.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime())[0].weight 
    : undefined;

  return (
    <div className="min-h-screen pb-32 selection:bg-clay/20 selection:text-ink">

      {/* Header - Elegant & Adaptive */}
      <header 
        className={`sticky top-0 z-50 px-6 py-4 flex items-center justify-center transition-all duration-500 ${
          scrolled ? 'glass shadow-sm py-3' : 'bg-transparent py-6'
        }`}
      >
        <div className={`flex items-center gap-3 transition-transform duration-500 ${scrolled ? 'scale-90' : 'scale-100'}`}>
           {profile.photoUrl ? (
             <div className="w-10 h-10 rounded-full overflow-hidden border-2 border-white shadow-md flex-shrink-0 ring-1 ring-sand/50">
               <img src={profile.photoUrl} alt="Profile" className="w-full h-full object-cover" />
             </div>
           ) : (
             <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center shadow-sm border border-sand">
               <PawPrint className="text-clay" fill="currentColor" size={20} strokeWidth={0} />
             </div>
           )}
           <h1 className="font-fangsong text-2xl tracking-wide text-ink truncate max-w-[200px] font-medium">
             {profile.name || 'My Pet Journal'}
           </h1>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="max-w-md mx-auto px-6 pt-2">

        {activeTab === 'profile' && (
          <ProfileSection profile={profile} setProfile={setProfile} />
        )}

        {activeTab === 'physical' && (
           <div className="animate-slide-up">
             <div className="mb-8 ml-1 flex flex-col items-center text-center">
               <span className="text-xs font-bold tracking-[0.2em] text-gold uppercase mb-2">Growth Tracker</span>
               <h2 className="font-fangsong text-3xl text-ink">Measurements</h2>
             </div>
             <PhysicalSection 
               records={physicalRecords} 
               addRecord={addPhysicalRecord} 
               deleteRecord={deletePhysicalRecord} 
             />
           </div>
        )}

        {activeTab === 'health' && (
          <div className="animate-slide-up">
            <div className="mb-8 ml-1 flex flex-col items-center text-center">
               <span className="text-xs font-bold tracking-[0.2em] text-gold uppercase mb-2">Medical History</span>
               <h2 className="font-fangsong text-3xl text-ink">Wellness Log</h2>
             </div>
            <HealthSection 
              records={healthRecords} 
              addRecord={addHealthRecord} 
              deleteRecord={deleteHealthRecord} 
            />
          </div>
        )}

        {activeTab === 'chat' && (
          <div className="animate-slide-up">
             <div className="mb-6 ml-1 flex flex-col items-center text-center">
               <span className="text-xs font-bold tracking-[0.2em] text-gold uppercase mb-2">AI Assistant</span>
               <h2 className="font-fangsong text-3xl text-ink">Companion</h2>
             </div>
             <ChatSection profile={profile} latestWeight={latestWeight} />
          </div>
        )}

      </main>

      {/* Floating Bottom Navigation - Premium Feel */}
      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 glass rounded-full px-2 py-2 shadow-float flex gap-1 items-center z-50">
        <div className="bg-ink/95 backdrop-blur-md rounded-full px-6 py-3 flex gap-8 shadow-inner border border-white/10">
          <NavBtn active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} icon={User} />
          <NavBtn active={activeTab === 'physical'} onClick={() => setActiveTab('physical')} icon={Activity} />
          <NavBtn active={activeTab === 'health'} onClick={() => setActiveTab('health')} icon={Heart} />
          <NavBtn active={activeTab === 'chat'} onClick={() => setActiveTab('chat')} icon={MessageCircle} />
        </div>
      </nav>

    </div>
  );
};

const NavBtn = ({ active, onClick, icon: Icon }: { active: boolean, onClick: () => void, icon: any }) => (
  <button 
    onClick={onClick}
    className={`relative group flex flex-col items-center justify-center w-8 h-8 transition-all duration-300 ${active ? 'text-white' : 'text-white/40 hover:text-white/70'}`}
  >
    <Icon size={20} strokeWidth={active ? 2.5 : 2} className={`transition-transform duration-300 ${active ? 'scale-110 -translate-y-0.5' : 'group-hover:scale-110'}`} />
    {active && <span className="absolute -bottom-2 w-1 h-1 bg-gold rounded-full animate-scale-in shadow-[0_0_8px_rgba(191,168,132,0.8)]" />}
  </button>
);

export default App;

