import React, { useState, useMemo } from 'react';
import { PhysicalRecord } from '../types';
import { generateId, formatDate, formatMonthYear } from '../utils';
import { Ruler, Weight, Plus, Trash2, ChevronDown, ChevronUp, X, Calendar as CalendarIcon } from 'lucide-react';

interface PhysicalSectionProps {
  records: PhysicalRecord[];
  addRecord: (record: PhysicalRecord) => void;
  deleteRecord: (id: string) => void;
}

export const PhysicalSection: React.FC<PhysicalSectionProps> = ({ records, addRecord, deleteRecord }) => {
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [newRecord, setNewRecord] = useState<Partial<PhysicalRecord>>({
    date: new Date().toISOString().split('T')[0],
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newRecord.weight && newRecord.date) {
      addRecord({
        id: generateId(),
        date: newRecord.date,
        weight: Number(newRecord.weight),
        height: newRecord.height ? Number(newRecord.height) : undefined,
        neck: newRecord.neck ? Number(newRecord.neck) : undefined,
        chest: newRecord.chest ? Number(newRecord.chest) : undefined,
        back: newRecord.back ? Number(newRecord.back) : undefined,
        notes: newRecord.notes || '',
      });
      setIsFormOpen(false);
      setNewRecord({ date: new Date().toISOString().split('T')[0] });
    }
  };

  const sortedRecords = [...records].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  const latest = sortedRecords[0];

  // Group records by Month Year
  const groupedRecords = useMemo(() => {
    const groups: Record<string, PhysicalRecord[]> = {};
    sortedRecords.forEach(record => {
      const date = new Date(record.date);
      const key = `${date.getFullYear()}-${date.getMonth()}`; // unique key
      if (!groups[key]) groups[key] = [];
      groups[key].push(record);
    });
    return groups;
  }, [sortedRecords]);

  // Sort keys descending
  const sortedKeys = Object.keys(groupedRecords).sort((a, b) => {
    const [yearA, monthA] = a.split('-').map(Number);
    const [yearB, monthB] = b.split('-').map(Number);
    return new Date(yearB, monthB).getTime() - new Date(yearA, monthA).getTime();
  });

  return (
    <div className="space-y-10 animate-slide-up">
      {/* Latest Stats Summary */}
      <div className="grid grid-cols-2 gap-6">
        <div className="bg-ink text-paper p-6 rounded-[2rem] shadow-float flex flex-col justify-between aspect-square relative overflow-hidden group">
            <div className="absolute top-0 right-0 w-24 h-24 bg-white/5 rounded-bl-full transition-transform group-hover:scale-110"></div>
            <div className="flex items-center gap-2 text-paper/60 text-[10px] font-bold tracking-widest uppercase font-sans z-10">
               <Weight size={14} /> Weight
            </div>
            <div className="mt-2 z-10">
              <span className="text-5xl font-fangsong leading-none tracking-tight">{latest?.weight ?? '--'}</span>
              <span className="text-sm ml-2 text-paper/60 font-serif italic">kg</span>
            </div>
        </div>
        <div className="bg-white p-6 rounded-[2rem] shadow-soft border border-white flex flex-col justify-between aspect-square relative group hover:shadow-float transition-shadow duration-500">
             <div className="flex items-center gap-2 text-pencil/80 text-[10px] font-bold tracking-widest uppercase font-sans">
               <Ruler size={14} /> Height
            </div>
            <div className="mt-2">
              <span className="text-5xl font-fangsong text-ink leading-none tracking-tight">{latest?.height ?? '--'}</span>
              <span className="text-sm ml-2 text-pencil font-serif italic">cm</span>
            </div>
        </div>
      </div>

      {/* Add Button */}
      {!isFormOpen && (
        <button 
          onClick={() => setIsFormOpen(true)}
          className="w-full py-5 rounded-2xl border border-dashed border-sand bg-transparent text-pencil hover:text-ink hover:border-gold hover:bg-white/50 transition-all flex items-center justify-center gap-2 font-sans text-sm tracking-widest uppercase"
        >
          <Plus size={16} /> New Record
        </button>
      )}

      {/* Input Form */}
      {isFormOpen && (
        <form onSubmit={handleSubmit} className="bg-white/90 backdrop-blur-md p-8 rounded-[2rem] shadow-float border border-white space-y-8 relative animate-scale-in">
          <div className="flex justify-between items-center">
            <h3 className="font-fangsong text-2xl text-ink">New Entry</h3>
            <button type="button" onClick={() => setIsFormOpen(false)} className="w-8 h-8 rounded-full bg-sand/30 flex items-center justify-center text-ink hover:bg-sand transition-colors">
                <X size={16}/>
            </button>
          </div>

          <div className="grid grid-cols-2 gap-8">
            <div className="col-span-2 group">
              <label className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1 block group-focus-within:text-clay font-sans">Date</label>
              <input 
                required
                type="date" 
                value={newRecord.date}
                onChange={e => setNewRecord({...newRecord, date: e.target.value})}
                className="w-full py-2 bg-transparent border-b border-sand focus:border-clay text-ink font-fangsong text-lg"
              />
            </div>
            <div className="group">
              <label className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1 block group-focus-within:text-clay font-sans">Weight (kg)</label>
              <input 
                required
                type="number" step="0.1"
                placeholder="0.0"
                value={newRecord.weight || ''}
                onChange={e => setNewRecord({...newRecord, weight: Number(e.target.value)})}
                className="w-full py-2 bg-transparent border-b border-sand focus:border-clay text-ink text-2xl font-fangsong placeholder-sand"
              />
            </div>
            <div className="group">
              <label className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1 block group-focus-within:text-clay font-sans">Height (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="0.0"
                value={newRecord.height || ''}
                onChange={e => setNewRecord({...newRecord, height: Number(e.target.value)})}
                className="w-full py-2 bg-transparent border-b border-sand focus:border-clay text-ink text-2xl font-fangsong placeholder-sand"
              />
            </div>
             <div className="group">
              <label className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1 block group-focus-within:text-clay font-sans">Chest (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="-"
                value={newRecord.chest || ''}
                onChange={e => setNewRecord({...newRecord, chest: Number(e.target.value)})}
                className="w-full py-2 bg-transparent border-b border-sand focus:border-clay text-ink text-xl font-fangsong placeholder-sand"
              />
            </div>
            <div className="group">
              <label className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1 block group-focus-within:text-clay font-sans">Neck (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="-"
                value={newRecord.neck || ''}
                onChange={e => setNewRecord({...newRecord, neck: Number(e.target.value)})}
                className="w-full py-2 bg-transparent border-b border-sand focus:border-clay text-ink text-xl font-fangsong placeholder-sand"
              />
            </div>
             <div className="group">
              <label className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1 block group-focus-within:text-clay font-sans">Back (cm)</label>
              <input 
                type="number" step="0.1"
                placeholder="-"
                value={newRecord.back || ''}
                onChange={e => setNewRecord({...newRecord, back: Number(e.target.value)})}
                className="w-full py-2 bg-transparent border-b border-sand focus:border-clay text-ink text-xl font-fangsong placeholder-sand"
              />
            </div>
          </div>

          <button type="submit" className="w-full py-4 bg-ink text-paper rounded-xl font-bold hover:bg-ink/90 transition-all shadow-lg shadow-ink/20 tracking-widest text-xs uppercase font-sans">
            Save Record
          </button>
        </form>
      )}

      {/* History List - Grouped by Month */}
      <div className="space-y-12">
        {sortedRecords.length === 0 && !isFormOpen && (
          <div className="text-center py-16 opacity-50">
             <div className="w-16 h-16 border-2 border-dashed border-pencil/30 rounded-full flex items-center justify-center mx-auto mb-4">
               <Ruler size={24} className="text-pencil" />
             </div>
             <p className="text-sm font-serif italic text-pencil">No measurements yet</p>
          </div>
        )}

        {sortedKeys.map(key => {
           const [year, month] = key.split('-');
           const groupDate = new Date(Number(year), Number(month));

           return (
             <div key={key} className="space-y-6">
                {/* Month Header - Elegant Typography */}
                <div className="flex items-center gap-4 sticky top-[4.5rem] z-10 py-2">
                   <h3 className="text-gold font-sans font-bold text-xs uppercase tracking-[0.2em] flex items-center gap-2 whitespace-nowrap bg-paper/80 backdrop-blur-md px-3 py-1 rounded-full border border-gold/20">
                     <CalendarIcon size={12} />
                     {formatMonthYear(groupDate.toISOString())}
                   </h3>
                   <div className="h-px flex-1 bg-gradient-to-r from-gold/30 to-transparent"></div>
                </div>

                {/* Records in this month */}
                <div className="space-y-4 pl-2">
                  {groupedRecords[key].map(record => (
                     <MeasurementCard key={record.id} record={record} onDelete={() => deleteRecord(record.id)} />
                  ))}
                </div>
             </div>
           );
        })}
      </div>
    </div>
  );
};

const MeasurementCard: React.FC<{ record: PhysicalRecord; onDelete: () => void }> = ({ record, onDelete }) => {
  const [expanded, setExpanded] = useState(false);
  const dateObj = new Date(record.date);

  return (
    <div className="bg-white rounded-2xl shadow-soft border border-white/60 overflow-hidden transition-all duration-300 hover:shadow-float group">
      <div 
        onClick={() => setExpanded(!expanded)}
        className="p-5 flex justify-between items-center cursor-pointer"
      >
        <div className="flex gap-6 items-center">
            <div className="text-center min-w-[50px] font-fangsong border-r border-sand/50 pr-6 py-1">
                <div className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1">{dateObj.toLocaleString('en-US', { weekday: 'short' })}</div>
                <div className="text-3xl text-ink leading-none">{dateObj.getDate()}</div>
            </div>

            <div className="flex flex-col">
                <div className="text-ink text-xl font-medium font-fangsong flex items-baseline gap-1">
                  {record.weight} 
                  <span className="text-sm text-pencil font-serif italic">kg</span>
                </div>
                {(record.height || record.chest) && (
                  <div className="text-[10px] text-pencil uppercase tracking-wider font-sans mt-1 flex gap-3 opacity-70">
                     {record.height && <span>H: {record.height}</span>}
                     {record.chest && <span>C: {record.chest}</span>}
                  </div>
                )}
            </div>
        </div>
        <div className="text-sand group-hover:text-warm transition-colors">
           {expanded ? <ChevronUp size={20} /> : <ChevronDown size={20} />}
        </div>
      </div>

      {expanded && (
        <div className="px-6 pb-6 pt-2 bg-sand/10">
          <div className="grid grid-cols-2 gap-y-4 gap-x-8 text-sm text-pencil mb-6 font-fangsong">
             {record.neck && <div className="flex justify-between border-b border-sand/30 pb-1"><span>Neck</span> <span className="text-ink">{record.neck} <span className="text-xs text-pencil/60">cm</span></span></div>}
             {record.chest && <div className="flex justify-between border-b border-sand/30 pb-1"><span>Chest</span> <span className="text-ink">{record.chest} <span className="text-xs text-pencil/60">cm</span></span></div>}
             {record.back && <div className="flex justify-between border-b border-sand/30 pb-1"><span>Back</span> <span className="text-ink">{record.back} <span className="text-xs text-pencil/60">cm</span></span></div>}
             {record.height && <div className="flex justify-between border-b border-sand/30 pb-1"><span>Height</span> <span className="text-ink">{record.height} <span className="text-xs text-pencil/60">cm</span></span></div>}
          </div>
          <button 
            onClick={(e) => { e.stopPropagation(); onDelete(); }}
            className="text-red-400 text-[10px] flex items-center gap-1.5 hover:text-red-600 transition-colors uppercase tracking-widest font-bold font-sans ml-auto"
          >
            <Trash2 size={12} /> Delete Entry
          </button>
        </div>
      )}
    </div>
  );
};

export interface VetContact {
  clinicName: string;
  doctorName?: string;
  phone: string;
  address: string;
}

export interface PetProfile {
  name: string;
  breed: string;
  gender: 'Male' | 'Female' | 'Other';
  birthDate: string; // ISO string YYYY-MM-DD
  microchipId: string;
  photoUrl: string | null;
  vetContact?: VetContact;
}

export interface PhysicalRecord {
  id: string;
  date: string;
  weight: number; // kg
  height?: number; // cm
  neck?: number; // cm
  chest?: number; // cm
  back?: number; // cm
  notes?: string;
}

export interface HealthRecord {
  id: string;
  type: 'Vaccine' | 'Deworming' | 'Vet Visit' | 'Other';
  date: string;
  title: string; // e.g., "Rabies Shot" or "Heartgard"
  location?: string;
  nextDueDate?: string; // For reminders
  notes?: string;
}

export type TabView = 'profile' | 'physical' | 'health';

import React, { useState, useEffect } from 'react';
import { PetProfile, PhysicalRecord, HealthRecord, TabView } from './types';
import { ProfileSection } from './components/ProfileSection';
import { PhysicalSection } from './components/PhysicalSection';
import { HealthSection } from './components/HealthSection';
import { User, Activity, Heart, PawPrint } from 'lucide-react';

const App: React.FC = () => {
  // --- State ---
  const [activeTab, setActiveTab] = useState<TabView>('profile');
  const [scrolled, setScrolled] = useState(false);

  const [profile, setProfile] = useState<PetProfile>(() => {
    const saved = localStorage.getItem('pawprint_profile');
    return saved ? JSON.parse(saved) : {
      name: '',
      breed: '',
      gender: 'Male',
      birthDate: '',
      microchipId: '',
      photoUrl: null,
      vetContact: {
        clinicName: '',
        phone: '',
        address: ''
      }
    };
  });

  const [physicalRecords, setPhysicalRecords] = useState<PhysicalRecord[]>(() => {
    const saved = localStorage.getItem('pawprint_physical');
    return saved ? JSON.parse(saved) : [];
  });

  const [healthRecords, setHealthRecords] = useState<HealthRecord[]>(() => {
    const saved = localStorage.getItem('pawprint_health');
    return saved ? JSON.parse(saved) : [];
  });

  // --- Effects ---
  useEffect(() => localStorage.setItem('pawprint_profile', JSON.stringify(profile)), [profile]);
  useEffect(() => localStorage.setItem('pawprint_physical', JSON.stringify(physicalRecords)), [physicalRecords]);
  useEffect(() => localStorage.setItem('pawprint_health', JSON.stringify(healthRecords)), [healthRecords]);

  // Scroll effect for header
  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // --- Handlers ---
  const addPhysicalRecord = (record: PhysicalRecord) => setPhysicalRecords([...physicalRecords, record]);
  const deletePhysicalRecord = (id: string) => setPhysicalRecords(physicalRecords.filter(r => r.id !== id));

  const addHealthRecord = (record: HealthRecord) => setHealthRecords([...healthRecords, record]);
  const deleteHealthRecord = (id: string) => setHealthRecords(healthRecords.filter(r => r.id !== id));

  return (
    <div className="min-h-screen pb-32 selection:bg-clay/20 selection:text-ink">

      {/* Header - Elegant & Adaptive */}
      <header 
        className={`sticky top-0 z-50 px-6 py-4 flex items-center justify-center transition-all duration-500 ${
          scrolled ? 'glass shadow-sm py-3' : 'bg-transparent py-6'
        }`}
      >
        <div className={`flex items-center gap-3 transition-transform duration-500 ${scrolled ? 'scale-90' : 'scale-100'}`}>
           {profile.photoUrl ? (
             <div className="w-10 h-10 rounded-full overflow-hidden border-2 border-white shadow-md flex-shrink-0 ring-1 ring-sand/50">
               <img src={profile.photoUrl} alt="Profile" className="w-full h-full object-cover" />
             </div>
           ) : (
             <div className="w-10 h-10 rounded-full bg-white flex items-center justify-center shadow-sm border border-sand">
               <PawPrint className="text-clay" fill="currentColor" size={20} strokeWidth={0} />
             </div>
           )}
           <h1 className="font-fangsong text-2xl tracking-wide text-ink truncate max-w-[200px] font-medium">
             {profile.name || 'My Pet Journal'}
           </h1>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="max-w-md mx-auto px-6 pt-2">

        {activeTab === 'profile' && (
          <ProfileSection profile={profile} setProfile={setProfile} />
        )}

        {activeTab === 'physical' && (
           <div className="animate-slide-up">
             <div className="mb-6 ml-1 flex flex-col items-center text-center">
               <span className="text-xs font-bold tracking-[0.2em] text-gold uppercase mb-2">Growth Tracker</span>
               <h2 className="font-fangsong text-3xl text-ink">Body Record</h2>
             </div>
             <PhysicalSection 
               records={physicalRecords} 
               addRecord={addPhysicalRecord} 
               deleteRecord={deletePhysicalRecord} 
             />
           </div>
        )}

        {activeTab === 'health' && (
          <div className="animate-slide-up">
            <div className="mb-6 ml-1 flex flex-col items-center text-center">
               <span className="text-xs font-bold tracking-[0.2em] text-gold uppercase mb-2">Medical History</span>
               <h2 className="font-fangsong text-3xl text-ink">Health Calendar</h2>
             </div>
            <HealthSection 
              records={healthRecords} 
              addRecord={addHealthRecord} 
              deleteRecord={deleteHealthRecord} 
            />
          </div>
        )}

      </main>

      {/* Floating Bottom Navigation - 3 Items */}
      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 glass rounded-full px-2 py-2 shadow-float flex gap-1 items-center z-50">
        <div className="bg-ink/95 backdrop-blur-md rounded-full px-8 py-3 flex gap-10 shadow-inner border border-white/10">
          <NavBtn active={activeTab === 'profile'} onClick={() => setActiveTab('profile')} icon={User} />
          <NavBtn active={activeTab === 'physical'} onClick={() => setActiveTab('physical')} icon={Activity} />
          <NavBtn active={activeTab === 'health'} onClick={() => setActiveTab('health')} icon={Heart} />
        </div>
      </nav>

    </div>
  );
};

const NavBtn = ({ active, onClick, icon: Icon }: { active: boolean, onClick: () => void, icon: any }) => (
  <button 
    onClick={onClick}
    className={`relative group flex flex-col items-center justify-center w-8 h-8 transition-all duration-300 ${active ? 'text-white' : 'text-white/40 hover:text-white/70'}`}
  >
    <Icon size={22} strokeWidth={active ? 2.5 : 2} className={`transition-transform duration-300 ${active ? 'scale-110 -translate-y-0.5' : 'group-hover:scale-110'}`} />
    {active && <span className="absolute -bottom-2.5 w-1 h-1 bg-gold rounded-full animate-scale-in shadow-[0_0_8px_rgba(191,168,132,0.8)]" />}
  </button>
);

export default App;

import React, { useState } from 'react';
import { PhysicalRecord } from '../types';
import { generateId, formatDate } from '../utils';
import { Weight, Ruler, ChevronLeft, ChevronRight, Plus, Trash2, X } from 'lucide-react';

interface PhysicalSectionProps {
  records: PhysicalRecord[];
  addRecord: (record: PhysicalRecord) => void;
  deleteRecord: (id: string) => void;
}

export const PhysicalSection: React.FC<PhysicalSectionProps> = ({ records, addRecord, deleteRecord }) => {
  // Calendar State
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDateStr, setSelectedDateStr] = useState(new Date().toISOString().split('T')[0]);
  const [isFormOpen, setIsFormOpen] = useState(false);

  // Form State
  const [newRecord, setNewRecord] = useState<Partial<PhysicalRecord>>({});

  // Calendar Logic
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = new Date(year, month, 1).getDay(); // 0 is Sunday

  const prevMonth = () => setCurrentDate(new Date(year, month - 1, 1));
  const nextMonth = () => setCurrentDate(new Date(year, month + 1, 1));

  // Get records for the selected date
  const selectedRecords = records.filter(r => r.date === selectedDateStr);

  const handleDateClick = (day: number) => {
    const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDateStr(dateStr);
  };

  const handleOpenForm = () => {
    setNewRecord({ date: selectedDateStr });
    setIsFormOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newRecord.weight && newRecord.date) {
      addRecord({
        id: generateId(),
        date: newRecord.date,
        weight: Number(newRecord.weight),
        height: newRecord.height ? Number(newRecord.height) : undefined,
        neck: newRecord.neck ? Number(newRecord.neck) : undefined,
        chest: newRecord.chest ? Number(newRecord.chest) : undefined,
        back: newRecord.back ? Number(newRecord.back) : undefined,
        notes: newRecord.notes || '',
      });
      setIsFormOpen(false);
      setNewRecord({});
    }
  };

  return (
    <div className="space-y-6 animate-slide-up">

      {/* Calendar Card */}
      <div className="bg-white/80 backdrop-blur-md rounded-[2rem] p-6 shadow-soft border border-white">
        {/* Header */}
        <div className="flex justify-between items-center mb-6">
          <button onClick={prevMonth} className="p-2 text-pencil hover:text-ink transition-colors"><ChevronLeft size={20}/></button>
          <h3 className="text-xl font-fangsong text-ink font-medium tracking-wide">
            {currentDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
          </h3>
          <button onClick={nextMonth} className="p-2 text-pencil hover:text-ink transition-colors"><ChevronRight size={20}/></button>
        </div>

        {/* Days of Week */}
        <div className="grid grid-cols-7 mb-2">
          {['S','M','T','W','T','F','S'].map((d, i) => (
            <div key={i} className="text-center text-[10px] font-bold text-gold uppercase tracking-wider py-2 font-sans">{d}</div>
          ))}
        </div>

        {/* Days Grid */}
        <div className="grid grid-cols-7 gap-y-2">
          {Array.from({ length: firstDayOfMonth }).map((_, i) => <div key={`empty-${i}`} />)}

          {Array.from({ length: daysInMonth }).map((_, i) => {
            const day = i + 1;
            const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
            const isSelected = dateStr === selectedDateStr;
            const hasRecord = records.some(r => r.date === dateStr);
            const isToday = dateStr === new Date().toISOString().split('T')[0];

            return (
              <div key={day} className="flex flex-col items-center">
                <button
                  onClick={() => handleDateClick(day)}
                  className={`w-9 h-9 rounded-full flex items-center justify-center text-sm font-fangsong transition-all duration-300 relative
                    ${isSelected ? 'bg-ink text-paper shadow-md scale-105' : 'text-ink hover:bg-sand/30'}
                    ${isToday && !isSelected ? 'border border-gold text-gold' : ''}
                  `}
                >
                  {day}
                  {hasRecord && (
                    <span className={`absolute bottom-1.5 w-1 h-1 rounded-full ${isSelected ? 'bg-gold' : 'bg-clay'}`} />
                  )}
                </button>
              </div>
            );
          })}
        </div>
      </div>

      {/* Selected Day Details */}
      <div className="space-y-4">
        <div className="flex justify-between items-end px-2">
           <div>
             <span className="text-xs font-bold tracking-[0.2em] text-pencil uppercase font-sans">Records For</span>
             <h4 className="text-2xl font-fangsong text-ink mt-1">{formatDate(selectedDateStr)}</h4>
           </div>
           {selectedRecords.length > 0 && (
             <button 
                onClick={handleOpenForm}
                className="w-10 h-10 rounded-full bg-white border border-sand flex items-center justify-center text-ink shadow-sm hover:bg-sand/20 transition-colors"
             >
                <Plus size={18} />
             </button>
           )}
        </div>

        {/* Empty State / Add Button */}
        {selectedRecords.length === 0 && !isFormOpen && (
          <div className="bg-white/50 border border-dashed border-sand rounded-3xl p-8 flex flex-col items-center justify-center text-center gap-4 group hover:border-gold/50 hover:bg-white/80 transition-all cursor-pointer" onClick={handleOpenForm}>
             <div className="w-12 h-12 rounded-full bg-sand/20 flex items-center justify-center text-pencil group-hover:text-gold group-hover:scale-110 transition-all duration-500">
               <Plus size={24} />
             </div>
             <p className="text-sm font-fangsong text-pencil">No records for this day.<br/>Tap to add a measurement.</p>
          </div>
        )}

        {/* Records List for Selected Day */}
        <div className="space-y-4">
           {selectedRecords.map(record => (
             <div key={record.id} className="bg-white rounded-2xl p-6 shadow-soft border border-white relative group animate-fade-in">
                <button 
                  onClick={() => deleteRecord(record.id)}
                  className="absolute top-4 right-4 text-sand hover:text-red-400 transition-colors p-2"
                >
                  <Trash2 size={16} />
                </button>

                <div className="grid grid-cols-2 gap-6">
                    <div>
                      <div className="flex items-center gap-2 text-gold text-[10px] font-bold uppercase tracking-widest font-sans mb-1">
                        <Weight size={12} /> Weight
                      </div>
                      <div className="text-4xl font-fangsong text-ink">
                        {record.weight} <span className="text-sm text-pencil font-serif italic">kg</span>
                      </div>
                    </div>

                    {(record.height || record.chest) && (
                      <div>
                        <div className="flex items-center gap-2 text-pencil text-[10px] font-bold uppercase tracking-widest font-sans mb-1">
                          <Ruler size={12} /> Size
                        </div>
                         <div className="space-y-1 mt-2">
                            {record.height && <div className="text-sm font-fangsong text-ink">H: {record.height}cm</div>}
                            {record.chest && <div className="text-sm font-fangsong text-ink">C: {record.chest}cm</div>}
                         </div>
                      </div>
                    )}
                </div>

                {(record.neck || record.back) && (
                    <div className="mt-4 pt-4 border-t border-sand/30 flex gap-6 text-sm font-fangsong text-pencil">
                       {record.neck && <span>Neck: <span className="text-ink">{record.neck}</span></span>}
                       {record.back && <span>Back: <span className="text-ink">{record.back}</span></span>}
                    </div>
                )}
             </div>
           ))}
        </div>
      </div>

      {/* Slide Up Form */}
      {isFormOpen && (
        <div className="fixed inset-0 z-[60] flex items-end justify-center pointer-events-none">
          <div className="absolute inset-0 bg-ink/20 backdrop-blur-sm pointer-events-auto" onClick={() => setIsFormOpen(false)} />
          <form onSubmit={handleSubmit} className="bg-[#FDFCF8] w-full max-w-md rounded-t-[2.5rem] p-8 shadow-2xl pointer-events-auto animate-slide-up relative">
             <div className="w-12 h-1 bg-sand rounded-full mx-auto mb-8 opacity-50" />

             <div className="flex justify-between items-center mb-8">
               <h3 className="font-fangsong text-2xl text-ink">New Measurement</h3>
               <button type="button" onClick={() => setIsFormOpen(false)} className="w-8 h-8 rounded-full bg-sand/30 flex items-center justify-center text-ink hover:bg-sand transition-colors">
                  <X size={16}/>
               </button>
             </div>

             <div className="grid grid-cols-2 gap-6 mb-8">
                <div className="col-span-2">
                   <label className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1 block font-sans">Date</label>
                   <input 
                    type="date"
                    required 
                    value={newRecord.date}
                    onChange={e => setNewRecord({...newRecord, date: e.target.value})}
                    className="w-full py-2 bg-transparent border-b border-sand focus:border-gold text-ink font-fangsong text-lg rounded-none"
                   />
                </div>
                <div>
                   <label className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1 block font-sans">Weight (kg)</label>
                   <input 
                    type="number" step="0.1" required
                    placeholder="0.0"
                    value={newRecord.weight || ''}
                    onChange={e => setNewRecord({...newRecord, weight: Number(e.target.value)})}
                    className="w-full py-2 bg-transparent border-b border-sand focus:border-gold text-ink font-fangsong text-2xl rounded-none placeholder-sand/50"
                   />
                </div>
                <div>
                   <label className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1 block font-sans">Height (cm)</label>
                   <input 
                    type="number" step="0.1"
                    placeholder="0.0"
                    value={newRecord.height || ''}
                    onChange={e => setNewRecord({...newRecord, height: Number(e.target.value)})}
                    className="w-full py-2 bg-transparent border-b border-sand focus:border-gold text-ink font-fangsong text-2xl rounded-none placeholder-sand/50"
                   />
                </div>
                 <div>
                   <label className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1 block font-sans">Neck (cm)</label>
                   <input 
                    type="number" step="0.1"
                    placeholder="-"
                    value={newRecord.neck || ''}
                    onChange={e => setNewRecord({...newRecord, neck: Number(e.target.value)})}
                    className="w-full py-2 bg-transparent border-b border-sand focus:border-gold text-ink font-fangsong text-xl rounded-none placeholder-sand/50"
                   />
                </div>
                 <div>
                   <label className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1 block font-sans">Chest (cm)</label>
                   <input 
                    type="number" step="0.1"
                    placeholder="-"
                    value={newRecord.chest || ''}
                    onChange={e => setNewRecord({...newRecord, chest: Number(e.target.value)})}
                    className="w-full py-2 bg-transparent border-b border-sand focus:border-gold text-ink font-fangsong text-xl rounded-none placeholder-sand/50"
                   />
                </div>
             </div>

             <button type="submit" className="w-full py-4 bg-ink text-paper rounded-xl font-bold hover:bg-ink/90 transition-all shadow-lg shadow-ink/20 tracking-widest text-xs uppercase font-sans">
               Save Record
             </button>
          </form>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { HealthRecord } from '../types';
import { generateId, formatDate } from '../utils';
import { ChevronLeft, ChevronRight, Plus, Trash2, X, Syringe, Bug, Clock, MapPin } from 'lucide-react';

interface HealthSectionProps {
  records: HealthRecord[];
  addRecord: (record: HealthRecord) => void;
  deleteRecord: (id: string) => void;
}

export const HealthSection: React.FC<HealthSectionProps> = ({ records, addRecord, deleteRecord }) => {
  // Calendar State
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDateStr, setSelectedDateStr] = useState(new Date().toISOString().split('T')[0]);
  const [isFormOpen, setIsFormOpen] = useState(false);

  // Form State
  const [activeType, setActiveType] = useState<'Vaccine' | 'Deworming'>('Vaccine');
  const [newRecord, setNewRecord] = useState<Partial<HealthRecord>>({});

  // Calendar Logic
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = new Date(year, month, 1).getDay();

  const prevMonth = () => setCurrentDate(new Date(year, month - 1, 1));
  const nextMonth = () => setCurrentDate(new Date(year, month + 1, 1));

  const handleDateClick = (day: number) => {
    const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
    setSelectedDateStr(dateStr);
  };

  const handleOpenForm = () => {
    setNewRecord({ date: selectedDateStr });
    setIsFormOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (newRecord.title && newRecord.date) {
      addRecord({
        id: generateId(),
        type: activeType,
        date: newRecord.date,
        title: newRecord.title,
        location: newRecord.location,
        nextDueDate: newRecord.nextDueDate,
        notes: newRecord.notes,
      });
      setIsFormOpen(false);
      setNewRecord({});
    }
  };

  // Filter records for selected date OR records that have a "Next Due" date on selected date
  const selectedDayRecords = records.filter(r => r.date === selectedDateStr);
  const selectedDayReminders = records.filter(r => r.nextDueDate === selectedDateStr);

  return (
    <div className="space-y-6 animate-slide-up">

      {/* Calendar Card */}
      <div className="bg-white/80 backdrop-blur-md rounded-[2rem] p-6 shadow-soft border border-white relative overflow-hidden">
        {/* Decorative corner */}
        <div className="absolute top-0 left-0 w-20 h-20 bg-gradient-to-br from-sage/10 to-transparent rounded-br-[4rem] pointer-events-none"></div>

        {/* Header */}
        <div className="flex justify-between items-center mb-6 relative z-10">
          <button onClick={prevMonth} className="p-2 text-pencil hover:text-ink transition-colors"><ChevronLeft size={20}/></button>
          <h3 className="text-xl font-fangsong text-ink font-medium tracking-wide">
            {currentDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
          </h3>
          <button onClick={nextMonth} className="p-2 text-pencil hover:text-ink transition-colors"><ChevronRight size={20}/></button>
        </div>

        {/* Days of Week */}
        <div className="grid grid-cols-7 mb-2 relative z-10">
          {['S','M','T','W','T','F','S'].map((d, i) => (
            <div key={i} className="text-center text-[10px] font-bold text-sage uppercase tracking-wider py-2 font-sans">{d}</div>
          ))}
        </div>

        {/* Days Grid */}
        <div className="grid grid-cols-7 gap-y-2 relative z-10">
          {Array.from({ length: firstDayOfMonth }).map((_, i) => <div key={`empty-${i}`} />)}

          {Array.from({ length: daysInMonth }).map((_, i) => {
            const day = i + 1;
            const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;
            const isSelected = dateStr === selectedDateStr;
            const isToday = dateStr === new Date().toISOString().split('T')[0];

            // Check for events on this day
            const dayEvents = records.filter(r => r.date === dateStr);
            const hasVaccine = dayEvents.some(r => r.type === 'Vaccine');
            const hasDeworm = dayEvents.some(r => r.type === 'Deworming');

            // Check for reminders (Next Due)
            const hasReminder = records.some(r => r.nextDueDate === dateStr);

            return (
              <div key={day} className="flex flex-col items-center">
                <button
                  onClick={() => handleDateClick(day)}
                  className={`w-9 h-9 rounded-full flex items-center justify-center text-sm font-fangsong transition-all duration-300 relative border-2 
                    ${isSelected 
                        ? 'bg-ink text-paper border-ink shadow-md scale-105' 
                        : hasReminder 
                            ? 'bg-white border-clay text-ink' // Outline for reminders
                            : 'border-transparent text-ink hover:bg-sand/30'
                    }
                    ${isToday && !isSelected && !hasReminder ? 'border-sage/50 bg-sage/10' : ''}
                  `}
                >
                  {day}

                  {/* Event Indicators */}
                  <div className="absolute -bottom-1 flex gap-0.5 justify-center">
                    {hasVaccine && <span className={`w-1 h-1 rounded-full ${isSelected ? 'bg-gold' : 'bg-blue-400'}`} />}
                    {hasDeworm && <span className={`w-1 h-1 rounded-full ${isSelected ? 'bg-gold' : 'bg-green-400'}`} />}
                  </div>
                </button>
              </div>
            );
          })}
        </div>

        {/* Legend */}
        <div className="mt-6 pt-4 border-t border-sand/30 flex justify-center gap-4 text-[10px] uppercase font-bold tracking-wider text-pencil font-sans">
             <div className="flex items-center gap-1.5"><span className="w-1.5 h-1.5 rounded-full bg-blue-400"></span> Vaccine</div>
             <div className="flex items-center gap-1.5"><span className="w-1.5 h-1.5 rounded-full bg-green-400"></span> Deworm</div>
             <div className="flex items-center gap-1.5"><span className="w-1.5 h-1.5 rounded-full border border-clay"></span> Due</div>
        </div>
      </div>

      {/* Selected Day Details */}
      <div className="space-y-4">
         <div className="flex justify-between items-end px-2">
           <div>
             <span className="text-xs font-bold tracking-[0.2em] text-pencil uppercase font-sans">Events On</span>
             <h4 className="text-2xl font-fangsong text-ink mt-1">{formatDate(selectedDateStr)}</h4>
           </div>
           {(selectedDayRecords.length > 0 || selectedDayReminders.length > 0) && (
             <button 
                onClick={handleOpenForm}
                className="w-10 h-10 rounded-full bg-white border border-sand flex items-center justify-center text-ink shadow-sm hover:bg-sand/20 transition-colors"
             >
                <Plus size={18} />
             </button>
           )}
        </div>

        {selectedDayRecords.length === 0 && selectedDayReminders.length === 0 && !isFormOpen && (
           <div className="bg-white/50 border border-dashed border-sand rounded-3xl p-8 flex flex-col items-center justify-center text-center gap-4 group hover:border-gold/50 hover:bg-white/80 transition-all cursor-pointer" onClick={handleOpenForm}>
             <div className="w-12 h-12 rounded-full bg-sand/20 flex items-center justify-center text-pencil group-hover:text-gold group-hover:scale-110 transition-all duration-500">
               <Plus size={24} />
             </div>
             <p className="text-sm font-fangsong text-pencil">No health events logged.<br/>Tap to add record.</p>
          </div>
        )}

        {/* Render "Due" Items First */}
        {selectedDayReminders.map(record => (
             <div key={`remind-${record.id}`} className="bg-[#FAF6F2] rounded-2xl p-5 shadow-sm border border-clay/30 relative flex gap-4 animate-fade-in">
                <div className="w-10 h-10 rounded-full bg-white border border-clay/20 flex items-center justify-center text-clay flex-shrink-0">
                   <Clock size={18} />
                </div>
                <div className="flex-1">
                    <div className="text-[10px] font-bold uppercase tracking-widest text-clay font-sans mb-1">Reminder Due</div>
                    <div className="text-lg font-fangsong text-ink font-medium">{record.title}</div>
                    <div className="text-xs text-pencil mt-1">From previous {record.type} record</div>
                </div>
             </div>
        ))}

        {/* Render Actual Records */}
        {selectedDayRecords.map(record => (
            <div key={record.id} className="bg-white rounded-2xl p-5 shadow-soft border border-white relative group animate-fade-in">
                <button 
                  onClick={() => deleteRecord(record.id)}
                  className="absolute top-4 right-4 text-sand hover:text-red-400 transition-colors p-1"
                >
                  <Trash2 size={16} />
                </button>

                <div className="flex gap-4">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center flex-shrink-0 ${
                        record.type === 'Vaccine' ? 'bg-blue-50 text-blue-500' : 'bg-green-50 text-green-500'
                    }`}>
                        {record.type === 'Vaccine' ? <Syringe size={18} /> : <Bug size={18} />}
                    </div>
                    <div>
                        <div className="text-[10px] font-bold uppercase tracking-widest text-pencil font-sans mb-1">{record.type}</div>
                        <div className="text-xl font-fangsong text-ink">{record.title}</div>

                        {(record.location || record.nextDueDate) && (
                            <div className="mt-3 space-y-1.5">
                                {record.location && (
                                    <div className="flex items-center gap-1.5 text-xs text-pencil font-fangsong">
                                        <MapPin size={12} className="text-warm" /> {record.location}
                                    </div>
                                )}
                                {record.nextDueDate && (
                                    <div className="flex items-center gap-1.5 text-xs text-clay font-medium font-fangsong">
                                        <Clock size={12} /> Next due: {formatDate(record.nextDueDate)}
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                </div>
            </div>
        ))}
      </div>

       {/* Slide Up Form */}
      {isFormOpen && (
        <div className="fixed inset-0 z-[60] flex items-end justify-center pointer-events-none">
          <div className="absolute inset-0 bg-ink/20 backdrop-blur-sm pointer-events-auto" onClick={() => setIsFormOpen(false)} />
          <form onSubmit={handleSubmit} className="bg-[#FDFCF8] w-full max-w-md rounded-t-[2.5rem] p-8 shadow-2xl pointer-events-auto animate-slide-up relative">
             <div className="w-12 h-1 bg-sand rounded-full mx-auto mb-8 opacity-50" />

             <div className="flex justify-between items-center mb-6">
               <h3 className="font-fangsong text-2xl text-ink">Health Record</h3>
               <button type="button" onClick={() => setIsFormOpen(false)} className="w-8 h-8 rounded-full bg-sand/30 flex items-center justify-center text-ink hover:bg-sand transition-colors">
                  <X size={16}/>
               </button>
             </div>

             {/* Type Selector */}
             <div className="flex bg-sand/20 p-1 rounded-xl mb-6">
                <button 
                  type="button"
                  onClick={() => setActiveType('Vaccine')}
                  className={`flex-1 py-2 rounded-lg text-sm font-medium transition-all duration-300 font-fangsong ${
                      activeType === 'Vaccine' ? 'bg-white text-ink shadow-sm' : 'text-pencil'
                  }`}
                >
                  Vaccine
                </button>
                <button 
                  type="button"
                  onClick={() => setActiveType('Deworming')}
                  className={`flex-1 py-2 rounded-lg text-sm font-medium transition-all duration-300 font-fangsong ${
                      activeType === 'Deworming' ? 'bg-white text-ink shadow-sm' : 'text-pencil'
                  }`}
                >
                  Deworming
                </button>
             </div>

             <div className="space-y-6">
                 <div>
                   <label className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1 block font-sans">Treatment Name</label>
                   <input 
                    type="text" required
                    placeholder={activeType === 'Vaccine' ? "e.g. Rabies, DHPP" : "e.g. Heartgard"}
                    value={newRecord.title || ''}
                    onChange={e => setNewRecord({...newRecord, title: e.target.value})}
                    className="w-full py-2 bg-transparent border-b border-sand focus:border-gold text-ink font-fangsong text-xl rounded-none placeholder-sand/50"
                   />
                </div>

                <div className="grid grid-cols-2 gap-6">
                   <div>
                       <label className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1 block font-sans">Date</label>
                       <input 
                        type="date" required
                        value={newRecord.date}
                        onChange={e => setNewRecord({...newRecord, date: e.target.value})}
                        className="w-full py-2 bg-transparent border-b border-sand focus:border-gold text-ink font-fangsong text-lg rounded-none"
                       />
                   </div>
                   <div>
                       <label className="text-[10px] text-clay font-bold tracking-widest uppercase mb-1 block font-sans">Next Due</label>
                       <input 
                        type="date"
                        value={newRecord.nextDueDate || ''}
                        onChange={e => setNewRecord({...newRecord, nextDueDate: e.target.value})}
                        className="w-full py-2 bg-transparent border-b border-sand focus:border-gold text-ink font-fangsong text-lg rounded-none"
                       />
                   </div>
                </div>

                 <div>
                   <label className="text-[10px] text-pencil font-bold tracking-widest uppercase mb-1 block font-sans">Clinic / Location</label>
                   <input 
                    type="text"
                    placeholder="e.g. City Vet"
                    value={newRecord.location || ''}
                    onChange={e => setNewRecord({...newRecord, location: e.target.value})}
                    className="w-full py-2 bg-transparent border-b border-sand focus:border-gold text-ink font-fangsong text-lg rounded-none placeholder-sand/50"
                   />
                </div>
             </div>

             <button type="submit" className="w-full py-4 mt-8 bg-ink text-paper rounded-xl font-bold hover:bg-ink/90 transition-all shadow-lg shadow-ink/20 tracking-widest text-xs uppercase font-sans">
               Save {activeType}
             </button>
          </form>
        </div>
      )}
    </div>
  );
};

export interface VetContact {
  clinicName: string;
  doctorName?: string;
  phone: string;
  address: string;
}

export interface PetProfile {
  name: string;
  breed: string;
  gender: 'Male' | 'Female' | 'Other';
  birthDate: string; // ISO string YYYY-MM-DD
  microchipId: string;
  photoUrl: string | null;
  vetContact?: VetContact;
}

export interface PhysicalRecord {
  id: string;
  date: string;
  weight: number; // kg
  height?: number; // cm
  neck?: number; // cm
  chest?: number; // cm
  back?: number; // cm
  notes?: string;
}

export interface HealthRecord {
  id: string;
  type: 'Vaccine' | 'Deworming' | 'Vet Visit' | 'Other';
  date: string;
  title: string; // e.g., "Rabies Shot" or "Heartgard"
  location?: string;
  nextDueDate?: string; // For reminders
  notes?: string;
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
}

export type TabView = 'profile' | 'physical' | 'health' | 'chat';
